# Dynamic Query to Filter User Data in MongoDB

Here are several approaches depending on your use case:

## 1. **Basic Query (Simple)**
```javascript
db.user_data.find({ gender: "Male" })
```

## 2. **Dynamic Query with Parameters (Recommended)**
```javascript
// Function to create dynamic filters
function filterUsers(filterCriteria) {
  return db.user_data.find(filterCriteria);
}

// Usage
filterUsers({ gender: "Male" })
```

## 3. **Advanced Dynamic Query Builder**
```javascript
class UserDataFilter {
  constructor() {
    this.query = {};
  }

  byGender(gender) {
    if (gender) {
      this.query.gender = gender;
    }
    return this;
  }

  byUsername(username) {
    if (username) {
      this.query.username = { $regex: username, $options: "i" };
    }
    return this;
  }

  execute() {
    return db.user_data.find(this.query);
  }
}

// Usage
const filter = new UserDataFilter()
  .byGender("Male")
  .byUsername("john")
  .execute();
```

## 4. **With Mongoose (Node.js)**
```javascript
const mongoose = require('mongoose');

// Schema
const userSchema = new mongoose.Schema({
  username: String,
  gender: String
});

const User = mongoose.model('user_data', userSchema);

// Simple query
async function getUsers(filterCriteria) {
  try {
    const users = await User.find(filterCriteria);
    return users;
  } catch (error) {
    console.error('Error fetching users:', error);
  }
}

// Usage
getUsers({ gender: "Male" });
```

## 5. **With Pagination and Sorting**
```javascript
async function getUsersWithOptions(filter, page = 1, limit = 10, sortBy = 'username') {
  const skip = (page - 1) * limit;

  return await db.collection('user_data')
    .find(filter)
    .sort({ [sortBy]: 1 })
    .skip(skip)
    .limit(limit)
    .toArray();
}

// Usage
getUsersWithOptions({ gender: "Male" }, 1, 10, 'username');
```

## 6. **With Projections (Select Specific Fields)**
```javascript
// Return only username and gender, exclude _id
db.user_data.find(
  { gender: "Male" },
  { projection: { username: 1, gender: 1, _id: 0 } }
);
```

## 7. **With Aggregation Pipeline (Complex Queries)**
```javascript
db.user_data.aggregate([
  { $match: { gender: "Male" } },
  { $project: { username: 1, gender: 1 } },
  { $sort: { username: 1 } },
  { $limit: 100 }
]);
```

## 8. **Complete Express.js Example**
```javascript
const express = require('express');
const app = express();

app.get('/users', async (req, res) => {
  try {
    const { gender, username, page = 1, limit = 10 } = req.query;

    // Build dynamic filter
    const filter = {};
    if (gender) filter.gender = gender;
    if (username) filter.username = { $regex: username, $options: "i" };

    // Execute query
    const skip = (page - 1) * limit;
    const users = await User.find(filter)
      .skip(skip)
      .limit(parseInt(limit))
      .lean();

    const total = await User.countDocuments(filter);

    res.json({
      success: true,
      total,
      page,
      limit,
      data: users
    });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

app.listen(3000);
```

## Performance Tips:
- ✅ **Create indexes** on frequently filtered fields:
  ```javascript
  db.user_data.createIndex({ gender: 1 })
  db.user_data.createIndex({ username: 1 })
  ```
- ✅ Use **projections** to fetch only needed fields
- ✅ Implement **pagination** for large datasets
- ✅ Use **aggregation pipeline** for complex filtering

Choose the approach based on your tech stack and requirements!

# Dynamic Query to Filter User Data in MongoDB

## Basic Query

```javascript
// Simple filter for Male users
db.user_data.find({ gender: "Male" })
```

## Dynamic Query with Parameters

```javascript
// Function to build dynamic queries
function filterUserData(filterCriteria) {
  return db.user_data.find(filterCriteria);
}

// Usage
filterUserData({ gender: "Male" });
```

## Advanced Dynamic Query Builder

```javascript
// More flexible approach
function buildDynamicQuery(filters) {
  const query = {};

  // Build query dynamically based on provided filters
  if (filters.gender) {
    query.gender = filters.gender;
  }
  if (filters.username) {
    query.username = { $regex: filters.username, $options: "i" }; // Case-insensitive
  }
  if (filters.userId) {
    query._id = ObjectId(filters.userId);
  }

  return db.user_data.find(query);
}

// Usage examples
buildDynamicQuery({ gender: "Male" });
buildDynamicQuery({ gender: "Male", username: "john" });
buildDynamicQuery({ gender: "Female", userId: "507f1f77bcf86cd799439011" });
```

## With Projection and Pagination

```javascript
function filterUserDataAdvanced(filters, options = {}) {
  const query = {};

  // Build filter query
  if (filters.gender) {
    query.gender = filters.gender;
  }
  if (filters.username) {
    query.username = { $regex: filters.username, $options: "i" };
  }

  // Options: projection, limit, skip, sort
  let cursor = db.user_data.find(query);

  // Projection (select specific fields)
  if (options.projection) {
    cursor = cursor.project(options.projection);
  }

  // Sorting
  if (options.sort) {
    cursor = cursor.sort(options.sort);
  }

  // Pagination
  if (options.skip) {
    cursor = cursor.skip(options.skip);
  }
  if (options.limit) {
    cursor = cursor.limit(options.limit);
  }

  return cursor.toArray();
}

// Usage
filterUserDataAdvanced(
  { gender: "Male" },
  {
    projection: { username: 1, gender: 1, _id: 1 },
    sort: { username: 1 },
    skip: 0,
    limit: 10
  }
);
```

## Mongoose (Node.js) Implementation

```javascript
const mongoose = require('mongoose');

// Define schema
const userSchema = new mongoose.Schema({
  username: String,
  gender: String
});

const UserData = mongoose.model('user_data', userSchema);

// Dynamic filter function
async function filterUsers(filters, options = {}) {
  try {
    const query = UserData.find();

    // Apply filters
    if (filters.gender) {
      query.where('gender').equals(filters.gender);
    }
    if (filters.username) {
      query.where('username').regex(new RegExp(filters.username, 'i'));
    }

    // Apply options
    if (options.projection) {
      query.select(options.projection);
    }
    if (options.sort) {
      query.sort(options.sort);
    }
    if (options.limit) {
      query.limit(options.limit);
    }
    if (options.skip) {
      query.skip(options.skip);
    }

    return await query.exec();
  } catch (error) {
    console.error('Error filtering users:', error);
  }
}

// Usage
filterUsers({ gender: "Male" }, { limit: 10, skip: 0 });
```

## Express.js API Endpoint

```javascript
const express = require('express');
const router = express.Router();

router.get('/users', async (req, res) => {
  try {
    const { gender, username, limit = 10, skip = 0 } = req.query;

    const filters = {};
    if (gender) filters.gender = gender;
    if (username) filters.username = { $regex: username, $options: 'i' };

    const users = await UserData.find(filters)
      .limit(parseInt(limit))
      .skip(parseInt(skip))
      .sort({ username: 1 });

    const total = await UserData.countDocuments(filters);

    res.json({
      total,
      count: users.length,
      data: users
    });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

module.exports = router;
```

## Query Examples

```javascript
// Simple filter
db.user_data.find({ gender: "Male" })

// With count
db.user_data.countDocuments({ gender: "Male" })

// Case-insensitive search
db.user_data.find({ gender: { $regex: "^male$", $options: "i" } })

// Multiple conditions (AND)
db.user_data.find({ gender: "Male", username: "john" })

// Multiple conditions (OR)
db.user_data.find({ $or: [{ gender: "Male" }, { username: "john" }] })

// With aggregation pipeline
db.user_data.aggregate([
  { $match: { gender: "Male" } },
  { $limit: 10 }
])
```

Choose the approach based on your:
- **Database Driver** (Native MongoDB, Mongoose, etc.)
- **Framework** (Node.js, Express, etc.)
- **Complexity** (Simple filters vs. advanced querying)

# Dynamic Query to Filter User Data in MongoDB

## Basic Query

```javascript
// Simple filter for Male users
db.user_data.find({ gender: "Male" })
```

## Dynamic Query Function

```javascript
/**
 * Dynamic query function to filter user data
 * @param {string} filterField - Field to filter by
 * @param {any} filterValue - Value to match
 * @returns {array} - Matching documents
 */
function filterUserData(filterField, filterValue) {
  const filter = {};
  filter[filterField] = filterValue;

  return db.user_data.find(filter).toArray();
}

// Usage
filterUserData("gender", "Male")
```

## Advanced Dynamic Query with Options

```javascript
/**
 * Advanced dynamic query with pagination and sorting
 */
function queryUserData(options = {}) {
  const {
    filterField = "gender",
    filterValue = "Male",
    sortBy = "_id",
    sortOrder = 1,
    limit = 10,
    skip = 0,
    projection = { username: 1, gender: 1 }
  } = options;

  const filter = {};
  filter[filterField] = filterValue;

  return db.user_data
    .find(filter, { projection })
    .sort({ [sortBy]: sortOrder })
    .skip(skip)
    .limit(limit)
    .toArray();
}

// Usage
queryUserData({
  filterField: "gender",
  filterValue: "Male",
  limit: 20,
  skip: 0,
  sortBy: "username"
})
```

## Using Mongoose (Node.js)

```javascript
const mongoose = require('mongoose');

// Define schema
const userSchema = new mongoose.Schema({
  username: String,
  gender: String
});

const User = mongoose.model('user_data', userSchema);

// Simple filter
async function getMaleUsers() {
  return await User.find({ gender: "Male" });
}

// Dynamic filter function
async function filterUsers(filterField, filterValue) {
  const filter = {};
  filter[filterField] = filterValue;

  return await User.find(filter);
}

// Advanced with options
async function queryUsers(options = {}) {
  const {
    filterField = "gender",
    filterValue = "Male",
    sortBy = "_id",
    limit = 10,
    skip = 0,
    select = "username gender"
  } = options;

  const filter = {};
  filter[filterField] = filterValue;

  return await User
    .find(filter)
    .select(select)
    .sort({ [sortBy]: 1 })
    .skip(skip)
    .limit(limit)
    .exec();
}

// Usage
await filterUsers("gender", "Male");
await queryUsers({ filterField: "gender", filterValue: "Male", limit: 20 });
```

## Multiple Dynamic Filters

```javascript
/**
 * Query with multiple dynamic filters
 */
async function multiFilterUsers(filters = {}) {
  const defaultFilters = {
    gender: "Male"
  };

  const combinedFilters = { ...defaultFilters, ...filters };

  return await User.find(combinedFilters);
}

// Usage
await multiFilterUsers({ gender: "Male", username: "john_doe" });
```

## Query with Aggregation Pipeline

```javascript
/**
 * Dynamic query using aggregation for complex filtering
 */
async function aggregateUserData(filterField, filterValue) {
  const matchStage = {};
  matchStage[filterField] = filterValue;

  return await User.aggregate([
    { $match: matchStage },
    { $project: { username: 1, gender: 1, _id: 1 } },
    { $limit: 100 }
  ]);
}

// Usage
await aggregateUserData("gender", "Male");
```

## Performance Tips

```javascript
// 1. Add index for frequently filtered fields
db.user_data.createIndex({ gender: 1 });

// 2. Use explain to analyze query performance
db.user_data.find({ gender: "Male" }).explain("executionStats");

// 3. Use batch processing for large datasets
async function processMaleUsersInBatches(batchSize = 1000) {
  const cursor = User.find({ gender: "Male" }).cursor();

  let batch = [];
  for (let doc = await cursor.next(); doc != null; doc = await cursor.next()) {
    batch.push(doc);

    if (batch.length === batchSize) {
      // Process batch
      console.log(`Processing ${batch.length} records`);
      batch = [];
    }
  }
}
```

Choose the approach that best fits your use case!

# Dynamic Query to Filter User Data in MongoDB

## Method 1: Basic Find Query (Simple)

```javascript
const mongoose = require('mongoose');

// Basic filter
const maleUsers = await db.collection('user_data').find({ gender: 'Male' }).toArray();
console.log(maleUsers);
```

## Method 2: Dynamic Query Builder (Recommended)

```javascript
async function filterUserData(filterCriteria) {
  const query = {};

  // Build dynamic query
  if (filterCriteria.gender) {
    query.gender = filterCriteria.gender;
  }
  if (filterCriteria.username) {
    query.username = { $regex: filterCriteria.username, $options: 'i' }; // Case-insensitive
  }

  const results = await db.collection('user_data').find(query).toArray();
  return results;
}

// Usage
const maleUsers = await filterUserData({ gender: 'Male' });
```

## Method 3: Mongoose Schema Approach

```javascript
const userSchema = new mongoose.Schema({
  username: String,
  gender: String
});

const User = mongoose.model('user_data', userSchema);

// Simple filter
const maleUsers = await User.find({ gender: 'Male' });

// Or with more options
const maleUsers = await User.find({ gender: 'Male' })
  .select('username gender')
  .limit(100)
  .sort({ username: 1 });
```

## Method 4: Advanced Dynamic Query with Pagination & Sorting

```javascript
async function dynamicUserFilter(filters, options = {}) {
  const {
    page = 1,
    limit = 10,
    sortBy = '_id',
    sortOrder = 1
  } = options;

  const query = {};

  // Dynamic filters
  Object.keys(filters).forEach(key => {
    if (filters[key]) {
      if (key === 'username') {
        query[key] = { $regex: filters[key], $options: 'i' };
      } else {
        query[key] = filters[key];
      }
    }
  });

  const skip = (page - 1) * limit;

  const results = await db.collection('user_data')
    .find(query)
    .sort({ [sortBy]: sortOrder })
    .skip(skip)
    .limit(limit)
    .toArray();

  const total = await db.collection('user_data').countDocuments(query);

  return {
    data: results,
    total,
    page,
    pages: Math.ceil(total / limit)
  };
}

// Usage
const result = await dynamicUserFilter(
  { gender: 'Male' },
  { page: 1, limit: 20, sortBy: 'username' }
);
```

## Method 5: Express.js Endpoint with Query Parameters

```javascript
app.get('/users', async (req, res) => {
  try {
    const { gender, username, page = 1, limit = 10 } = req.query;

    const query = {};
    if (gender) query.gender = gender;
    if (username) query.username = { $regex: username, $options: 'i' };

    const skip = (page - 1) * limit;

    const users = await db.collection('user_data')
      .find(query)
      .skip(skip)
      .limit(parseInt(limit))
      .toArray();

    const total = await db.collection('user_data').countDocuments(query);

    res.json({
      success: true,
      data: users,
      pagination: {
        page: parseInt(page),
        limit: parseInt(limit),
        total,
        pages: Math.ceil(total / limit)
      }
    });
  } catch (error) {
    res.status(500).json({ success: false, error: error.message });
  }
});

// Usage: GET /users?gender=Male&page=1&limit=20
```

## Method 6: Using Aggregation Pipeline (for complex queries)

```javascript
async function filterWithAggregation(filterCriteria) {
  const pipeline = [
    {
      $match: filterCriteria // { gender: 'Male' }
    },
    {
      $group: {
        _id: '$gender',
        count: { $sum: 1 },
        users: { $push: '$$ROOT' }
      }
    }
  ];

  const results = await db.collection('user_data').aggregate(pipeline).toArray();
  return results;
}

// Usage
const results = await filterWithAggregation({ gender: 'Male' });
```

## Performance Tips

```javascript
// 1. Create index on frequently filtered columns
db.collection('user_data').createIndex({ gender: 1 });
db.collection('user_data').createIndex({ username: 1 });

// 2. Use projection to limit fields
const maleUsers = await User.find({ gender: 'Male' })
  .select('username gender')
  .lean(); // For faster performance

// 3. Batch processing for large datasets
const batch = await User.find({ gender: 'Male' })
  .batchSize(1000)
  .cursor();
```

Choose the method based on your needs:
- **Method 1**: Simple, quick filtering
- **Method 2**: Reusable, flexible filtering
- **Method 3**: When using Mongoose ODM
- **Method 4**: With pagination & sorting
- **Method 5**: REST API integration
- **Method 6**: Complex analytics queries

# Dynamic MongoDB Query for User Data

Here are several approaches to filter user data dynamically:

## 1. **Basic MongoDB Query (Node.js)**

```javascript
const mongoose = require('mongoose');

// Simple filter
const maleUsers = await db.collection('user_data').find({ gender: 'Male' }).toArray();
console.log(maleUsers);
```

## 2. **Dynamic Query Builder (Recommended)**

```javascript
async function filterUsers(filterCriteria) {
  const query = {};

  // Build dynamic query
  if (filterCriteria.gender) {
    query.gender = filterCriteria.gender;
  }
  if (filterCriteria.username) {
    query.username = { $regex: filterCriteria.username, $options: 'i' };
  }

  const result = await db.collection('user_data').find(query).toArray();
  return result;
}

// Usage
const maleUsers = await filterUsers({ gender: 'Male' });
```

## 3. **Advanced with Pagination & Sorting**

```javascript
async function filterUsersPaginated(filterCriteria, page = 1, limit = 10) {
  const query = {};

  // Build query dynamically
  Object.keys(filterCriteria).forEach(key => {
    if (filterCriteria[key]) {
      if (key === 'username') {
        query[key] = { $regex: filterCriteria[key], $options: 'i' };
      } else {
        query[key] = filterCriteria[key];
      }
    }
  });

  const skip = (page - 1) * limit;

  const result = await db.collection('user_data')
    .find(query)
    .skip(skip)
    .limit(limit)
    .toArray();

  const total = await db.collection('user_data').countDocuments(query);

  return {
    data: result,
    total,
    pages: Math.ceil(total / limit)
  };
}

// Usage
const maleUsers = await filterUsersPaginated({ gender: 'Male' }, 1, 20);
```

## 4. **Using Mongoose Schema**

```javascript
const userSchema = new mongoose.Schema({
  username: String,
  gender: String
});

const User = mongoose.model('user_data', userSchema);

async function filterUsers(filterCriteria) {
  return await User.find(filterCriteria);
}

// Usage
const maleUsers = await filterUsers({ gender: 'Male' });
```

## 5. **Complex Dynamic Filtering**

```javascript
async function buildDynamicQuery(filters) {
  const query = {};

  const filterMap = {
    gender: (value) => ({ gender: value }),
    username: (value) => ({ username: { $regex: value, $options: 'i' } }),
    ageRange: (value) => ({ age: { $gte: value.min, $lte: value.max } })
  };

  Object.keys(filters).forEach(key => {
    if (filters[key] && filterMap[key]) {
      Object.assign(query, filterMap[key](filters[key]));
    }
  });

  return query;
}

// Usage
const query = await buildDynamicQuery({ gender: 'Male' });
const results = await db.collection('user_data').find(query).toArray();
```

## 6. **With Aggregation Pipeline**

```javascript
async function filterWithAggregation(filterCriteria) {
  const pipeline = [
    {
      $match: filterCriteria
    },
    {
      $project: {
        username: 1,
        gender: 1
      }
    }
  ];

  return await db.collection('user_data').aggregate(pipeline).toArray();
}

// Usage
const maleUsers = await filterWithAggregation({ gender: 'Male' });
```

## 7. **REST API Endpoint Example**

```javascript
app.get('/users', async (req, res) => {
  try {
    const { gender, username, page = 1, limit = 10 } = req.query;

    const filterCriteria = {};
    if (gender) filterCriteria.gender = gender;
    if (username) filterCriteria.username = { $regex: username, $options: 'i' };

    const results = await filterUsersPaginated(filterCriteria, page, limit);
    res.json(results);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

// Query: GET /users?gender=Male&page=1&limit=20
```

## Query Comparison

| Method | Use Case | Performance |
|--------|----------|-------------|
| **Basic find()** | Simple filters | ⭐⭐⭐⭐⭐ |
| **Dynamic builder** | Multiple filters | ⭐⭐⭐⭐ |
| **Aggregation** | Complex transformations | ⭐⭐⭐⭐ |
| **Mongoose** | Schema validation | ⭐⭐⭐ |

## Best Practices

✅ **Index your filters**
```javascript
db.collection('user_data').createIndex({ gender: 1 });
```

✅ **Validate input**
```javascript
if (!['Male', 'Female', 'Other'].includes(filterCriteria.gender)) {
  throw new Error('Invalid gender value');
}
```

✅ **Use projection for large datasets**
```javascript
.find(query, { projection: { username: 1, gender: 1 } })
```

Choose **Method 2 or 3** for production applications as they balance flexibility with performance! 🚀

# Dynamic MongoDB Query for User Filtering

## Basic Query

```javascript
// Simple filter for Male users
db.user_data.find({ gender: "Male" });
```

## Dynamic Query Function

```javascript
// Function to dynamically filter users
function getUsersByGender(genderValue) {
  return db.user_data.find({ gender: genderValue });
}

// Usage
getUsersByGender("Male");
```

## Advanced Dynamic Query with Multiple Filters

```javascript
// More flexible function with multiple filter options
function filterUsers(filters = {}) {
  const query = {};

  if (filters.gender) query.gender = filters.gender;
  if (filters.username) query.username = { $regex: filters.username, $options: "i" };
  if (filters._id) query._id = filters._id;

  return db.user_data.find(query);
}

// Usage examples
filterUsers({ gender: "Male" });
filterUsers({ gender: "Male", username: "john" });
filterUsers({ gender: "Female" });
```

## With Pagination & Sorting

```javascript
function filterUsersPaginated(filters = {}, page = 1, limit = 10, sort = {}) {
  const query = {};

  if (filters.gender) query.gender = filters.gender;
  if (filters.username) query.username = { $regex: filters.username, $options: "i" };

  const skip = (page - 1) * limit;

  return db.user_data
    .find(query)
    .sort(sort)
    .skip(skip)
    .limit(limit);
}

// Usage
filterUsersPaginated({ gender: "Male" }, 1, 20, { username: 1 });
```

## Using Node.js with MongoDB Driver

```javascript
const { MongoClient } = require("mongodb");

async function filterUsers(genderFilter) {
  const client = new MongoClient(process.env.MONGODB_URI);

  try {
    await client.connect();
    const db = client.db("your_database");
    const collection = db.collection("user_data");

    const query = { gender: genderFilter };
    const results = await collection.find(query).toArray();

    return results;
  } finally {
    await client.close();
  }
}

// Usage
filterUsers("Male").then(users => console.log(users));
```

## Using Mongoose (Node.js)

```javascript
const userSchema = new mongoose.Schema({
  username: String,
  gender: String
});

const User = mongoose.model("user_data", userSchema);

// Simple filter
async function getMaleUsers() {
  return await User.find({ gender: "Male" });
}

// Dynamic filter
async function filterUsers(filterObj) {
  return await User.find(filterObj);
}

// Usage
filterUsers({ gender: "Male" });
filterUsers({ gender: "Male", username: "john" });
```

## With Aggregation Pipeline (Best for Complex Queries)

```javascript
db.user_data.aggregate([
  {
    $match: { gender: "Male" }
  },
  {
    $group: {
      _id: "$gender",
      count: { $sum: 1 },
      users: { $push: "$username" }
    }
  }
]);
```

## Adding Indexes for Performance

```javascript
// Create index for faster queries
db.user_data.createIndex({ gender: 1 });
db.user_data.createIndex({ gender: 1, username: 1 });
```

Choose the approach based on your needs:
- **Simple queries** → Use basic `find()`
- **Multiple filters** → Use dynamic function
- **Large datasets** → Add pagination & indexes
- **Complex operations** → Use aggregation pipeline
